        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté garlic and ginger in oil.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Add cream and cooked chicken.\n6. Simmer 10 more minutes. Serve with rice.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with meat and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles\nShrimp or tofu\nEggs\nBean sprouts\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Stir-fry shrimp/tofu until cooked, set aside.\n3. Scramble eggs in the wok.\n4. Add drained noodles and sauce (tamarind, fish sauce, sugar).\n5. Toss with protein, bean sprouts, and green onions.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Preheat oven to 425°F. Butter ramekins.\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla until thick.\n4. Fold chocolate mixture into eggs, then fold in flour.\n5. Pour into ramekins.\n6. Bake 12-14 minutes (center should be soft).\n7. Invert onto plates and serve immediately.", AverageRating = 4.9, RatingCount = 30 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce\nParmesan cheese\nCroutons\nCaesar dressing\nLemon juice\nGarlic\nAnchovy paste", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk garlic, anchovy paste, lemon juice, and olive oil.\n3. Toss lettuce with dressing.\n4. Add shaved parmesan and croutons.\n5. Season with black pepper.", AverageRating = 4.0, RatingCount = 6 },
    };

    private static readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic pasta, pizza, and Mediterranean flavors", Icon = "🍕" },
        new RecipeCategory { Name = "Indian", Description = "Rich curries, aromatic spices, and vibrant dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Mexican", Description = "Bold flavors with chilies, lime, and fresh ingredients", Icon = "🌮" },
        new RecipeCategory { Name = "Asian", Description = "Stir-fries, noodles, and umami-packed meals", Icon = "🍜" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats and indulgent baked goods", Icon = "🍰" },
        new RecipeCategory { Name = "Salads", Description = "Fresh, healthy, and colorful combinations", Icon = "🥗" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
    }

    public void SubmitRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}
