@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (recipes.Count == 0)
    {
        <p class="text-muted">No recipes found in this category yet.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-4">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="text-muted">
                                ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

<div class="container">
    @if (recipe is null)
    {
        <p class="text-danger">Recipe not found.</p>
    }
    else
    {
        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
                <li class="breadcrumb-item active">@recipe.Title</li>
            </ol>
        </nav>

        <h1>@recipe.Title</h1>
        <p class="text-muted">Category: @recipe.Category</p>

        <div class="mb-4">
            <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />
        </div>

        <div class="row">
            <div class="col-md-4">
                <div class="card mb-3">
                    <div class="card-header"><strong>Ingredients</strong></div>
                    <div class="card-body">
                        <ul class="list-unstyled mb-0">
                            @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                            {
                                <li>• @ingredient</li>
                            }
                        </ul>
                    </div>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header"><strong>Instructions</strong></div>
                    <div class="card-body">
                        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <p>@step</p>
                        }
                    </div>
