@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <h1>Submit a Recipe</h1>
    <p>Share your favorite recipe with the community!</p>

    @if (successMessage is not null)
    {
        <div class="alert alert-success">@successMessage</div>
    }

    <EditForm Model="recipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="recipe.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="recipe.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Name">@cat.Name</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" rows="6" @bind-Value="recipe.Ingredients"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, sliced" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" rows="8" @bind-Value="recipe.Steps"
                           placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. ..." />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
</div>

@code {
    private Recipe recipe = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(recipe.Title) || string.IsNullOrWhiteSpace(recipe.Category))
            return;

        RecipeService.SubmitRecipe(recipe);
        successMessage = $"'{recipe.Title}' submitted successfully!";
        recipe = new();
    }
}
